  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

async function sbFetch(path, options = {}) {
  const resp = await httpReq(SUPABASE_URL + path, {
    headers: { ...sbHeaders, ...(options.headers || {}) },
    method: options.method || 'GET',
    body: options.body ? JSON.stringify(options.body) : undefined
  });
  const text = await resp.text();
  if (!resp.ok) throw new Error('Supabase ' + (options.method || 'GET') + ' ' + path.split('?')[0] + ' failed (' + resp.status + '): ' + text.substring(0, 300));
  return text ? JSON.parse(text) : null;
}

const input = $input.first().json;
const body = input.body || input;
const { token, vendor_id, marketplaces } = body;

if (!token || !vendor_id) {
  return [{ json: { success: false, error: 'Missing token or vendor_id' } }];
}

try {
  // ========== AUTH ==========
  const authResp = await httpReq('https://api.katalync.com/webhook/auth-verify', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token })
  });
  const authData = await authResp.json();
  if (!authData.success) {
    return [{ json: { success: false, error: authData.error || 'Token invalid or expired' } }];
  }

  // Upsert user
  const upsertData = await sbFetch('/users?on_conflict=email', {
    method: 'POST',
    headers: { 'Prefer': 'resolution=merge-duplicates,return=representation' },
    body: [{ email: authData.email, name: authData.name || authData.email, password_hash: 'oauth-managed', role: authData.role || 'user', company: authData.company || null, lang: authData.lang || 'es', onboarded: authData.onboarded || false, subscription_status: authData.subscription_status || 'active', last_login_at: new Date().toISOString() }]
  });
  const user_id = upsertData && upsertData.length > 0 ? upsertData[0].id : null;
  if (!user_id) return [{ json: { success: false, error: 'Failed to provision user' } }];

  // ========== VENDOR ==========
  const vendors = await sbFetch('/vendors?id=eq.' + vendor_id + '&user_id=eq.' + user_id + '&select=*');
  if (!vendors || vendors.length === 0) {
    return [{ json: { success: false, error: 'Vendor not found or access denied' } }];
  }
  const vendor = vendors[0];

  // Determine marketplaces to process
  const mktList = Array.isArray(marketplaces) && marketplaces.length > 0
    ? marketplaces
    : (vendor.config && vendor.config.marketplaces ? vendor.config.marketplaces : ['sprinter_es']);

  // ========== READ UNCONVERTED PRODUCTS ==========
  const rawProducts = await sbFetch(
    '/vendor_products?vendor_id=eq.' + vendor_id +
    '&or=(sprinter_product.is.null,sync_status.in.(synced,new,changed))' +
    '&order=created_at.asc&limit=1000'
  );

  if (!Array.isArray(rawProducts) || rawProducts.length === 0) {
    return [{ json: { success: true, converted: 0, total: 0, message: 'No products to convert — all already converted', marketplaces: mktList } }];
  }

  // ========== MAP TO CONVERTER FORMAT ==========
  const mappedProducts = rawProducts.map(p => {
    const rd = p.raw_data || {};
    const hasDiscount = rd.compare_at_price && parseFloat(rd.compare_at_price) > (p.price || 0);
    return {
      sku: p.sku || '',
      ean: p.ean || '',
      nombre: p.name || '',
      marca: p.brand || '',
      categoria: p.category || '',
      precio: hasDiscount ? String(rd.compare_at_price) : (p.price ? String(p.price) : '0'),
      stock: p.stock != null ? String(p.stock) : '0',
      imagen: p.image_url || '',
      color: rd.variant_option1 || '',
      talla: rd.variant_option2 || '',
      peso: rd.variant_weight ? String(rd.variant_weight) : '',
      'discount-price': hasDiscount ? String(p.price) : '',
      variant_group_code: p.sku ? p.sku.replace(/-\d+$/, '') : ''
    };
  });

  // ========== PROCESS IN BATCHES PER MARKETPLACE ==========
  const BATCH_SIZE = 30;
  let totalConverted = 0;
  let totalErrors = 0;
  const mktResults = {};

  for (const mkt of mktList) {
    let mktConverted = 0;
    let mktErrors = 0;
    const batchErrors = [];

    for (let i = 0; i < mappedProducts.length; i += BATCH_SIZE) {
      const batch = mappedProducts.slice(i, i + BATCH_SIZE);
      try {
        const resp = await httpReq('https://api.katalync.com/webhook/process-products', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            token: token,
            products: batch,
            marketplace: mkt,
            vendor_id: vendor_id,
            convertImages: true,
            generateDescriptions: true,
            generateTitles: true
          }),
          timeout: 180000
        });

        if (resp.ok) {
          mktConverted += batch.length;
        } else {
          const errText = await resp.text();
          mktErrors += batch.length;
          batchErrors.push('Batch ' + Math.floor(i / BATCH_SIZE + 1) + ': HTTP ' + resp.status + ' - ' + errText.substring(0, 200));
        }
      } catch (e) {
        mktErrors += batch.length;
        batchErrors.push('Batch ' + Math.floor(i / BATCH_SIZE + 1) + ': ' + e.message);
      }

      // Brief pause between batches
      if (i + BATCH_SIZE < mappedProducts.length) {
        await new Promise(r => setTimeout(r, 500));
      }
    }

    totalConverted += mktConverted;
    totalErrors += mktErrors;
    mktResults[mkt] = { converted: mktConverted, errors: mktErrors, batch_errors: batchErrors.length > 0 ? batchErrors.slice(0, 5) : undefined };
  }

  // ========== UPDATE SYNC STATUS ==========
  try {
    await sbFetch('/vendor_products?vendor_id=eq.' + vendor_id + '&sprinter_product=not.is.null', {
      method: 'PATCH',
      headers: { 'Prefer': 'return=minimal' },
      body: { sync_status: 'converted' }
    });
  } catch (e) {}

  // Update vendor with conversion info
  try {
    const convertedCount = await sbFetch('/vendor_products?vendor_id=eq.' + vendor_id + '&sync_status=eq.converted&select=id', {
      headers: { 'Prefer': 'count=exact' }
    });
    await sbFetch('/vendors?id=eq.' + vendor_id, {
      method: 'PATCH',
      body: {
        sync_status: totalConverted === 0 && totalErrors === 0 ? (vendor.sync_status || 'synced') : totalErrors > 0 ? 'converted_with_errors' : 'converted',
        config: { ...(vendor.config || {}), marketplaces: mktList, last_convert_at: new Date().toISOString() }
      }
    });
  } catch (e) {}

  return [{ json: {
    success: true,
    converted: totalConverted,
    errors: totalErrors,
    total: rawProducts.length,
    marketplaces: mktResults,
    vendor_id: vendor_id,
    vendor_name: vendor.name
  } }];

} catch (e) {
  return [{ json: { success: false, error: 'Auto-convert error: ' + e.message } }];
}
